import JSZip from 'jszip'

/**
 * Bundle an array of { file_path, content } objects into a ZIP Blob.
 *
 * @param {Array<{ file_path: string, content: string }>} files
 * @param {string} projectName
 * @returns {Promise<Blob>}
 */
export async function bundleFilesToZip(files, projectName) {
  const zip = new JSZip()

  const safeName = projectName.replace(/[^a-z0-9]/gi, '-').toLowerCase()
  const folder   = zip.folder(safeName)

  for (const file of files) {
    const content =
      typeof file.content === 'string'
        ? file.content
        : JSON.stringify(file.content, null, 2)
    folder.file(file.file_path, content)
  }

  // Auto-generate a README
  folder.file(
    'README.md',
    `# ${projectName}\n\nGenerated by [Atlas.AI](https://atlasai.dev)\n\n## Getting Started\n\n\`\`\`bash\nnpm install\nnpm run dev\n\`\`\`\n\n## Project Structure\n\nThis project was generated by 5 parallel AI agents:\n- **Frontend** — pages & components\n- **Backend** — API routes\n- **Database** — SQL schema & seed data\n- **Security** — middleware & auth helpers\n- **Tests** — Jest + React Testing Library\n`
  )

  // Add package.json if the project uses Next.js
  const hasNextJs = files.some(
    (f) => f.file_path.includes('app/') || f.file_path.endsWith('.jsx')
  )
  if (hasNextJs) {
    folder.file(
      'package.json',
      JSON.stringify(
        {
          name:    safeName,
          version: '0.1.0',
          private: true,
          scripts: {
            dev:   'next dev',
            build: 'next build',
            start: 'next start',
            lint:  'next lint',
            test:  'jest',
          },
          dependencies: {
            next:                  '^14.0.0',
            react:                 '^18.0.0',
            'react-dom':           '^18.0.0',
            '@supabase/supabase-js': '^2.0.0',
            '@supabase/ssr':        '^0.1.0',
          },
          devDependencies: {
            tailwindcss:              '^3.0.0',
            postcss:                  '^8.0.0',
            autoprefixer:             '^10.0.0',
            jest:                     '^29.0.0',
            '@testing-library/react': '^14.0.0',
          },
        },
        null,
        2
      )
    )
  }

  return zip.generateAsync({ type: 'blob' })
}
